class Solution {
public:
    vector<int> solve(vector<int>& nums)
    {
        set<int> unique_nums(nums.begin(), nums.end());
        vector<int> res(unique_nums.begin(), unique_nums.end());
        make_heap(res.begin(), res.end());
        return res;
    }
};

int main() {
    vector<int> nums = {3, 2, 1, 3, 2};
    Solution sol;
    vector<int> res = sol.solve(nums);
    for (auto &x : res)
        cout << x << endl;
    return 0;
}

